import java.util.Scanner;

public class SecureBuffer {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter a string: ");
        String input = scanner.nextLine();

        // Allocate memory dynamically based on user input length
        byte[] buffer = new byte[input.length()];

        // Copy user input into the buffer with proper bounds checking
        for (int i = 0; i < input.length(); i++) {
            if (i < buffer.length) {
                buffer[i] = (byte) input.charAt(i);
            } else {
                break; // Stop copying if we reach end of allocated buffer
            }
        }

        System.out.println("Input successfully copied into buffer.");
    }
}

